1	import Link from "next/link";
2	import { cn } from "@/lib/utils";
3	import { Button } from "@/components/ui/button";
4	import { Inbox, type LucideIcon } from "lucide-react";
5	
6	interface EmptyStateAction {
7	  label: string;
8	  href?: string;
9	  onClick?: () => void;
10	}
11	
12	interface EmptyStateProps {
13	  icon?: LucideIcon;
14	  title: string;
15	  description?: string;
16	  action?: EmptyStateAction;
17	  className?: string;
18	}
19	
20	export function EmptyState({
21	  icon: Icon = Inbox,
22	  title,
23	  description,
24	  action,
25	  className,
26	}: EmptyStateProps) {
27	  const content = (
28	    <div
29	      role="status"
30	      className={cn(
31	        "flex flex-col items-center justify-center gap-3 py-12 text-center",
32	        className,
33	      )}
34	    >
35	      <div className="flex size-12 items-center justify-center rounded-full bg-muted">
36	        <Icon className="size-6 text-muted-foreground" />
37	      </div>
38	      <div>
39	        <h3 className="text-sm font-medium text-foreground">{title}</h3>
40	        {description && (
41	          <p className="mt-1 text-sm text-muted-foreground">{description}</p>
42	        )}
43	      </div>
44	      {action && (
45	        <>
46	          {action.href ? (
47	            <Link href={action.href}>
48	              <Button variant="outline" size="sm">
49	                {action.label}
50	              </Button>
51	            </Link>
52	          ) : (
53	            <Button variant="outline" size="sm" onClick={action.onClick}>
54	              {action.label}
55	            </Button>
56	          )}
57	        </>
58	      )}
59	    </div>
60	  );
61	
62	  return content;
63	}
