1	"use client"
2	
3	import * as React from "react"
4	import { Menu } from "@base-ui/react/menu"
5	
6	import { cn } from "@/lib/utils"
7	import { ChevronDownIcon, CheckIcon } from "lucide-react"
8	
9	interface SelectContextValue {
10	  value?: string
11	  onValueChange?: (value: string) => void
12	}
13	
14	const SelectContext = React.createContext<SelectContextValue>({})
15	
16	function Select({ value, onValueChange, children, ...props }: Menu.Root.Props & { value?: string; onValueChange?: (value: string) => void }) {
17	  return (
18	    <SelectContext.Provider value={{ value, onValueChange }}>
19	      <Menu.Root data-slot="select" {...props}>
20	        {children}
21	      </Menu.Root>
22	    </SelectContext.Provider>
23	  )
24	}
25	
26	function SelectTrigger({ className, children, ...props }: Menu.Trigger.Props) {
27	  return (
28	    <Menu.Trigger
29	      data-slot="select-trigger"
30	      className={cn(
31	        "flex h-8 w-full items-center justify-between gap-2 rounded-lg border border-input bg-background px-3 py-2 text-sm outline-none focus-visible:border-ring focus-visible:ring-3 focus-visible:ring-ring/50 disabled:pointer-events-none disabled:opacity-50",
32	        className
33	      )}
34	      {...props}
35	    >
36	      {children}
37	      <ChevronDownIcon className="size-4 text-muted-foreground" />
38	    </Menu.Trigger>
39	  )
40	}
41	
42	function SelectValue({ placeholder, className, children, ...props }: React.ComponentProps<"span"> & { placeholder?: string }) {
43	  return (
44	    <span
45	      data-slot="select-value"
46	      className={cn("text-sm", !children && "text-muted-foreground", className)}
47	      {...props}
48	    >
49	      {children ?? placeholder}
50	    </span>
51	  )
52	}
53	
54	function SelectContent({
55	  align = "start",
56	  alignOffset = 0,
57	  side = "bottom",
58	  sideOffset = 4,
59	  className,
60	  ...props
61	}: Menu.Popup.Props &
62	  Pick<Menu.Positioner.Props, "align" | "alignOffset" | "side" | "sideOffset">) {
63	  return (
64	    <Menu.Portal>
65	      <Menu.Positioner
66	        className="isolate z-50 outline-none"
67	        align={align}
68	        alignOffset={alignOffset}
69	        side={side}
70	        sideOffset={sideOffset}
71	      >
72	        <Menu.Popup
73	          data-slot="select-content"
74	          className={cn(
75	            "z-50 max-h-(--available-height) w-(--anchor-width) min-w-32 origin-(--transform-origin) overflow-x-hidden overflow-y-auto rounded-lg bg-popover p-1 text-popover-foreground shadow-md ring-1 ring-foreground/10 duration-100 outline-none data-[side=bottom]:slide-in-from-top-2 data-[side=inline-end]:slide-in-from-left-2 data-[side=inline-start]:slide-in-from-right-2 data-[side=left]:slide-in-from-right-2 data-[side=right]:slide-in-from-left-2 data-[side=top]:slide-in-from-bottom-2 data-open:animate-in data-open:fade-in-0 data-open:zoom-in-95 data-closed:animate-out data-closed:overflow-hidden data-closed:fade-out-0 data-closed:zoom-out-95",
76	            className
77	          )}
78	          {...props}
79	        />
80	      </Menu.Positioner>
81	    </Menu.Portal>
82	  )
83	}
84	
85	function SelectItem({ value, className, children, ...props }: Menu.Item.Props & { value: string }) {
86	  const ctx = React.useContext(SelectContext)
87	  const isSelected = ctx.value === value
88	
89	  return (
90	    <Menu.Item
91	      data-slot="select-item"
92	      data-selected={isSelected || undefined}
93	      onClick={(event) => {
94	        ctx.onValueChange?.(value)
95	        props.onClick?.(event)
96	      }}
97	      className={cn(
98	        "relative flex cursor-default items-center gap-1.5 rounded-md py-1 pl-1.5 pr-8 text-sm outline-hidden select-none focus:bg-accent focus:text-accent-foreground data-disabled:pointer-events-none data-disabled:opacity-50 data-selected:font-medium [&_svg]:pointer-events-none [&_svg]:shrink-0 [&_svg:not([class*='size-'])]:size-4",
99	        className
100	      )}
101	      {...props}
102	    >
103	      {children}
104	      {isSelected && (
105	        <span className="pointer-events-none absolute right-2 flex items-center justify-center">
106	          <CheckIcon className="size-3.5" />
107	        </span>
108	      )}
109	    </Menu.Item>
110	  )
111	}
112	
113	function SelectGroup({ ...props }: Menu.Group.Props) {
114	  return <Menu.Group data-slot="select-group" {...props} />
115	}
116	
117	function SelectLabel({ className, ...props }: Menu.GroupLabel.Props) {
118	  return (
119	    <Menu.GroupLabel
120	      data-slot="select-label"
121	      className={cn("px-1.5 py-1 text-xs font-medium text-muted-foreground", className)}
122	      {...props}
123	    />
124	  )
125	}
126	
127	function SelectSeparator({ className, ...props }: Menu.Separator.Props) {
128	  return (
129	    <Menu.Separator
130	      data-slot="select-separator"
131	      className={cn("-mx-1 my-1 h-px bg-border", className)}
132	      {...props}
133	    />
134	  )
135	}
136	
137	export {
138	  Select,
139	  SelectTrigger,
140	  SelectValue,
141	  SelectContent,
142	  SelectItem,
143	  SelectGroup,
144	  SelectLabel,
145	  SelectSeparator,
146	}
