1	import { Badge } from "@/components/ui/badge";
2	import { cn } from "@/lib/utils";
3	
4	export type AssetInstanceStatus =
5	  | "IN_STOCK"
6	  | "AVAILABLE"
7	  | "ASSIGNED"
8	  | "IN_USE"
9	  | "RETURNING"
10	  | "REPAIRING"
11	  | "TRANSFERRING"
12	  | "LOST"
13	  | "SCRAPPED";
14	
15	const statusConfig: Record<
16	  AssetInstanceStatus,
17	  { label: string; variant: "default" | "secondary" | "outline" | "destructive" | "ghost" | "link"; className?: string }
18	> = {
19	  IN_STOCK: { label: "在库", variant: "secondary" },
20	  AVAILABLE: { label: "可用", variant: "default", className: "bg-status-green/10 text-status-green hover:bg-status-green/20 dark:text-status-green" },
21	  ASSIGNED: { label: "已分配", variant: "default", className: "bg-status-blue/10 text-status-blue hover:bg-status-blue/20 dark:text-status-blue" },
22	  IN_USE: { label: "使用中", variant: "default", className: "bg-status-teal/10 text-status-teal hover:bg-status-teal/20 dark:text-status-teal" },
23	  RETURNING: { label: "归还中", variant: "outline", className: "border-status-yellow text-status-yellow" },
24	  REPAIRING: { label: "维修中", variant: "outline", className: "border-status-orange text-status-orange" },
25	  TRANSFERRING: { label: "调拨中", variant: "outline", className: "border-status-purple text-status-purple" },
26	  LOST: { label: "丢失", variant: "destructive" },
27	  SCRAPPED: { label: "已报废", variant: "secondary" },
28	};
29	
30	interface AssetStatusBadgeProps {
31	  status: AssetInstanceStatus;
32	  className?: string;
33	}
34	
35	export function AssetStatusBadge({ status, className }: AssetStatusBadgeProps) {
36	  const config = statusConfig[status] ?? {
37	    label: status,
38	    variant: "outline" as const,
39	  };
40	
41	  return (
42	    <Badge
43	      variant={config.variant}
44	      className={cn(config.className, className)}
45	    >
46	      {config.label}
47	    </Badge>
48	  );
49	}
