9	interface ChatMessage {
10	  role: "user" | "assistant";
11	  content: string;
12	}
13	
14	interface ChatResponse {
15	  ok: boolean;
16	  data?: {
17	    intent?: string;
18	    reply: string;
19	    needConfirmation?: boolean;
20	    pendingAction?: {
21	      type: string;
22	      description: string;
23	      params: Record<string, unknown>;
24	    } | null;
25	    confirmationToken?: string;
26	  };
27	  error?: string;
28	  reply?: string;
29	}
30	
31	export default function ChatPage() {
32	  const { user } = useAuth();
33	  const router = useRouter();
34	  const [messages, setMessages] = useState<ChatMessage[]>([
35	    { role: "assistant", content: "你好！我是 IT 助手，有什么可以帮助你的吗？你可以查询资产信息、保修状态、工单进度，或提交申领/报修申请。" },
36	  ]);
37	  const [input, setInput] = useState("");
38	  const [loading, setLoading] = useState(false);
39	  const [degraded, setDegraded] = useState(false);
40	  const [confirmDialog, setConfirmDialog] = useState<{
41	    description: string;
42	    actionType: string;
43	    token: string;
44	  } | null>(null);
45	  const messagesEndRef = useRef<HTMLDivElement>(null);
46	
47	  // Auto scroll to bottom
48	  useEffect(() => {
49	    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
50	  }, [messages]);
51	
52	  const handleSend = async () => {
53	    if (!input.trim() || loading) return;
54	    const userMsg: ChatMessage = { role: "user", content: input.trim() };
55	    setMessages((prev) => [...prev, userMsg]);
56	    setInput("");
57	    setLoading(true);
58	
59	    try {
60	      const history = messages.slice(1).map((m) => ({ role: m.role, content: m.content }));
61	      const res = await apiFetch<ChatResponse>("/api/ai/chat", {
62	        method: "POST",
63	        body: { message: userMsg.content, history },
64	      });
65	
66	      if (res.ok && res.data) {
67	        setDegraded(false);
68	        const assistantMsg: ChatMessage = {
69	          role: "assistant",
70	          content: res.data.reply,
71	        };
72	        setMessages((prev) => [...prev, assistantMsg]);
73	
74	        if (res.data.needConfirmation && res.data.pendingAction && res.data.confirmationToken) {
75	          setConfirmDialog({
76	            description: res.data.pendingAction.description,
77	            actionType: res.data.pendingAction.type,
78	            token: res.data.confirmationToken,
79	          });
80	        }
81	      } else {
82	        // Degraded mode or error
83	        setDegraded(true);
84	        const reply = res.reply ?? res.data?.reply ?? "AI 助手暂时不可用";
85	        setMessages((prev) => [...prev, { role: "assistant", content: reply }]);
86	      }
87	    } catch (err) {
88	      setDegraded(true);
89	      setMessages((prev) => [
90	        ...prev,
91	        { role: "assistant", content: "AI 助手暂时不可用，你可以通过「我的资产」查看资产信息，或通过「申领设备」/「报修」提交申请。" },
92	      ]);
93	    } finally {
94	      setLoading(false);
95	    }
96	  };
97	
98	  const handleConfirm = () => {
99	    if (!confirmDialog) return;
100	    const { actionType } = confirmDialog;
101	    setConfirmDialog(null);
102	    if (actionType === "create_apply") {
103	      router.push("/apply");
104	    } else if (actionType === "create_repair") {
105	      router.push("/tickets");
106	    }
107	  };
108	
109	  const handleKeyDown = (e: React.KeyboardEvent) => {
110	    if (e.key === "Enter" && !e.shiftKey) {
111	      e.preventDefault();
112	      handleSend();
113	    }
114	  };
115	
116	  return (
117	    <div className="flex flex-1 flex-col h-full max-w-2xl mx-auto w-full p-4">
118	      <h1 className="text-2xl font-bold mb-4">AI 助手</h1>
119	
120	      {/* Chat Messages */}
121	      <div className="flex-1 overflow-y-auto space-y-4 mb-4 min-h-0">
122	        {messages.map((msg, i) => (
123	          <div key={i} className={`flex ${msg.role === "user" ? "justify-end" : "justify-start"}`}>
124	            <div
125	              className={`max-w-[80%] rounded-lg px-4 py-2 ${
126	                msg.role === "user"
127	                  ? "bg-primary text-primary-foreground"
128	                  : "bg-muted text-foreground"
129	              }`}
130	            >
131	              <p className="text-sm whitespace-pre-wrap">{msg.content}</p>
132	            </div>
133	          </div>
134	        ))}
135	
136	        {/* Typing Indicator */}
137	        {loading && (
138	          <div className="flex justify-start">
139	            <div className="rounded-lg bg-muted px-4 py-3">
140	              <div className="flex gap-1">
141	                <span className="h-2 w-2 animate-bounce rounded-full bg-muted-foreground/40 [animation-delay:0ms]" />
142	                <span className="h-2 w-2 animate-bounce rounded-full bg-muted-foreground/40 [animation-delay:150ms]" />
143	                <span className="h-2 w-2 animate-bounce rounded-full bg-muted-foreground/40 [animation-delay:300ms]" />
144	              </div>
145	            </div>
146	          </div>
147	        )}
148	
149	        {/* Degraded Hint */}
150	        {degraded && !loading && (
151	          <div className="rounded-lg bg-yellow-50 dark:bg-yellow-900/20 px-3 py-2 text-xs text-yellow-800 dark:text-yellow-200">
152	            AI 服务降级中，部分功能可能不可用
153	          </div>
154	        )}
155	
156	        <div ref={messagesEndRef} />
157	      </div>
158	
159	      {/* Input Area */}
160	      <div className="flex gap-2">
161	        <textarea
162	          value={input}
163	          onChange={(e) => setInput(e.target.value)}
164	          onKeyDown={handleKeyDown}
165	          placeholder="输入你的问题..."
166	          rows={1}
167	          className="flex-1 rounded-lg border border-input bg-background px-3 py-2 text-sm outline-none focus-visible:border-ring focus-visible:ring-3 focus-visible:ring-ring/50 resize-none"
168	        />
169	        <Button onClick={handleSend} disabled={loading || !input.trim()}>
170	          发送
171	        </Button>
172	      </div>
173	
174	      {/* Confirmation Dialog */}
175	      {confirmDialog && (
176	        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50">
177	          <div className="w-full max-w-sm rounded-lg bg-background p-6 space-y-4">
178	            <h3 className="font-semibold">确认操作</h3>
179	            <p className="text-sm text-muted-foreground">{confirmDialog.description}</p>
180	            <div className="flex justify-end gap-2">
181	              <Button variant="outline" onClick={() => setConfirmDialog(null)}>
182	                取消
183	              </Button>
184	              <Button onClick={handleConfirm}>
185	                确认
186	              </Button>
187	            </div>
188	          </div>
189	        </div>
190	      )}
191	    </div>
192	  );
193	}
