18	}
19	
20	export default function NotificationsPage() {
21	  const { user, setUnreadNotifications } = useAuth();
22	  const [notifications, setNotifications] = useState<NotificationItem[]>([]);
23	  const [loading, setLoading] = useState(true);
24	  const [error, setError] = useState<string | null>(null);
25	
26	  const fetchNotifications = async () => {
27	    setLoading(true);
28	    setError(null);
29	    try {
30	      // Derive notifications from tickets
31	      const res = await apiFetch<PaginatedResponse<{ id: string; type: string; status: string; createdAt: string; updatedAt: string }>>(
32	        "/api/tickets",
33	        { params: { page: 1, pageSize: 50 } },
34	      );
35	      const items: NotificationItem[] = res.data.map((t) => ({
36	        id: t.id,
37	        type: "APPROVAL_RESULT",
38	        title: t.type === "APPLY" ? "申领工单" : t.type === "REPAIR" ? "报修工单" : t.type === "RETURN" ? "归还工单" : "调拨工单",
39	        body: `状态更新为: ${t.status}`,
40	        read: ["COMPLETED", "CANCELLED", "REJECTED"].includes(t.status),
41	        relatedTicketId: t.id,
42	        createdAt: t.updatedAt,
43	      }));
44	      setNotifications(items);
45	      const unread = items.filter((n) => !n.read).length;
46	      setUnreadNotifications(unread);
47	    } catch (err) {
48	      setError(err instanceof Error ? err.message : "加载失败");
49	    } finally {
50	      setLoading(false);
51	    }
52	  };
53	
54	  useEffect(() => {
55	    fetchNotifications();
56	  }, []);
57	
58	  const handleMarkAllRead = () => {
59	    setNotifications((prev) => prev.map((n) => ({ ...n, read: true })));
60	    setUnreadNotifications(0);
61	  };
62	
63	  const typeIcon = (type: string) => {
64	    const map: Record<string, string> = {
65	      APPROVAL_REQUEST: "📋",
66	      APPROVAL_RESULT: "✅",
67	      PICKUP_READY: "📦",
68	      REPAIR_UPDATE: "🔧",
69	      WARRANTY_EXPIRY: "⚠️",
70	      TRANSFER_REQUEST: "🔄",
71	      RETURN_SUBMITTED: "📤",
72	    };
73	    return map[type] ?? "📩";
74	  };
75	
76	  if (loading) {
77	    return (
78	      <div className="flex flex-1 items-center justify-center p-4">
79	        <div className="w-full max-w-2xl space-y-4">
80	          <div className="h-8 w-32 animate-pulse rounded bg-muted" />
81	          {[1, 2, 3, 4, 5].map((i) => (
82	            <div key={i} className="h-20 animate-pulse rounded-lg bg-muted" />
83	          ))}
84	        </div>
85	      </div>
86	    );
87	  }
88	
89	  if (error !== null) {
90	    return (
91	      <div className="flex flex-1 flex-col items-center justify-center gap-4 p-4">
92	        <p className="text-destructive">{error}</p>
93	        <Button onClick={fetchNotifications}>重试</Button>
94	      </div>
95	    );
96	  }
97	
98	  return (
99	    <div className="flex flex-1 flex-col gap-6 p-4 max-w-2xl mx-auto w-full">
100	      <div className="flex items-center justify-between">
101	        <h1 className="text-2xl font-bold">通知</h1>
102	        {notifications.length > 0 && (
103	          <Button variant="outline" size="sm" onClick={handleMarkAllRead}>
104	            全部标记已读
105	          </Button>
106	        )}
107	      </div>
108	
109	      {notifications.length === 0 ? (
110	        <div className="rounded-lg border border-dashed p-12 text-center">
111	          <p className="text-muted-foreground">暂无通知</p>
112	        </div>
113	      ) : (
114	        <div className="space-y-2">
115	          {notifications.map((n) => (
116	            <div
117	              key={n.id}
118	              className={`rounded-lg border p-4 transition-colors hover:bg-muted/50 ${
119	                !n.read ? "border-l-4 border-l-primary" : ""
120	              }`}
121	            >
122	              <div className="flex items-start gap-3">
123	                <span className="text-xl">{typeIcon(n.type)}</span>
124	                <div className="flex-1 min-w-0">
125	                  <div className="flex items-center justify-between">
126	                    <p className={`text-sm font-medium ${!n.read ? "text-foreground" : "text-muted-foreground"}`}>
127	                      {n.title}
128	                    </p>
129	                    <span className="text-xs text-muted-foreground whitespace-nowrap ml-2">
130	                      {new Date(n.createdAt).toLocaleString("zh-CN")}
131	                    </span>
132	                  </div>
133	                  <p className="mt-1 text-sm text-muted-foreground line-clamp-2">{n.body}</p>
134	                  {n.relatedTicketId && (
